import { useEffect, useState } from "react"
import API from "../services/api"

export default function ChatHistory() {

    const [chats, setChats] = useState([])

    const fetchChats = async () => {

        try {

            const token = localStorage.getItem("token")

            const res = await API.get(

                "/chat/history",

                {
                    headers: {
                        Authorization: `Bearer ${token}`
                    }
                }

            )

            setChats(res.data)

        } catch (error) {

            console.log(error)

        }

    }

    useEffect(() => {

        fetchChats()

    }, [])

    const deleteChat = async (id) => {

        try {

            const token = localStorage.getItem("token")

            await API.delete(

                `/chat/${id}`,

                {
                    headers: {
                        Authorization: `Bearer ${token}`
                    }
                }

            )

            fetchChats()

        } catch (error) {

            console.log(error)

        }

    }

    const clearHistory = async () => {

        if (!window.confirm("Clear all chat history?"))
            return

        try {

            const token = localStorage.getItem("token")

            await API.delete(

                "/chat/clear",

                {
                    headers: {
                        Authorization: `Bearer ${token}`
                    }
                }

            )

            setChats([])

        } catch (error) {

            console.log(error)

        }

    }

    return (

        <div
            style={{
                maxWidth: "900px",
                margin: "30px auto",
                padding: "20px"
            }}
        >

            <div
                style={{
                    display: "flex",
                    justifyContent: "space-between",
                    marginBottom: "20px"
                }}
            >

                <h1>Chat History</h1>

                <button
                    onClick={clearHistory}
                >
                    Clear All
                </button>

            </div>

            {

                chats.length === 0 ?

                    <p>No chat history found.</p>

                    :

                    chats.map(chat => (

                        <div

                            key={chat._id}

                            style={{
                                border: "1px solid #ddd",
                                borderRadius: "10px",
                                padding: "15px",
                                marginBottom: "15px"
                            }}

                        >

                            <p>

                                <strong>You:</strong>

                                {chat.question}

                            </p>

                            <p>

                                <strong>AI:</strong>

                                {chat.answer}

                            </p>

                            <small>

                                {new Date(
                                    chat.createdAt
                                ).toLocaleString()}

                            </small>

                            <br />

                            <button

                                onClick={() =>
                                    deleteChat(chat._id)
                                }

                                style={{
                                    marginTop: "10px"
                                }}

                            >

                                Delete

                            </button>

                        </div>

                    ))

            }

        </div>

    )

}
